#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Models;
using PVZEngine.Definitions;
using PVZEngine.Entities;
//using UnityEditorInternal;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.popCaptain_Animation)]
    public class PopCaptain_AnimationBehaviour : EnemyCommonAnimationBehaviour
    {
        public PopCaptain_AnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            bool noAnchor = PopCaptain.NoAnchor(entity);
            entity.SetModelProperty("NoAnchor", noAnchor);

            var animatorInterface = entity.GetAnimatorInterface(VanillaAnimatorKeys.main);
            if (animatorInterface != null)
            {
                var stateNumber = entity.State;
                var animationState = GetAnimationState(stateNumber);
                bool holdingAnchor = !noAnchor && (animationState == ANIMATION_STATE_WALK || animationState == ANIMATION_STATE_IDLE);
                var targetWeight = holdingAnchor ? 1f : 0f;
                var weight = animatorInterface.GetLayerWeight("AnchorArm");
                weight = weight * 0.5f + targetWeight * 0.5f;
                animatorInterface.SetLayerWeight("AnchorArm", weight);
            }
        }
        public override int GetAnimationState(int state)
        {
            switch (state)
            {
                case STATE_SMASH_DOWN:
                    return ANIMATION_STATE_SMASH_DOWN;
                case STATE_SMASH_UP:
                    return ANIMATION_STATE_SMASH_UP;
            }
            return base.GetAnimationState(state);
        }
        public const int STATE_SMASH_DOWN = VanillaEnemyStates.POP_CAPTAIN_SMASH_DOWN;
        public const int STATE_SMASH_UP = VanillaEnemyStates.POP_CAPTAIN_SMASH_UP;

        public const int ANIMATION_STATE_SMASH_DOWN = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 0;
        public const int ANIMATION_STATE_SMASH_UP = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 1;
    }
}
